mapper.sql:
from aiw_product p where p.is_deleted = 0

    and (lower(p.product_name) like concat('%', lower(#{criteria.keyword}), '%')
      or lower(p.product_code) like concat('%', lower(#{criteria.keyword}), '%')
      or lower(p.product_no) like concat('%', lower(#{criteria.keyword}), '%'))

and p.product_type = #{criteria.productType}
and p.trade_status = #{criteria.tradeStatus.code}
and p.risk_level = #{criteria.riskLevel}

    and p.currency = upper(#{criteria.currency})

mapper.select:
select p.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
